import{_ as e,o as t,c as n,a0 as r}from"./chunks/framework.Bogozrur.js";const c=JSON.parse('{"title":"RAG（检索增强生成）","description":"","frontmatter":{},"headers":[],"relativePath":"notes/rag.md","filePath":"notes/rag.md","lastUpdated":null}'),o={name:"notes/rag.md"};function i(l,a,s,d,g,p){return t(),n("div",null,[...a[0]||(a[0]=[r(`<h1 id="rag-检索增强生成" tabindex="-1">RAG（检索增强生成） <a class="header-anchor" href="#rag-检索增强生成" aria-label="Permalink to &quot;RAG（检索增强生成）&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么？ <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么？&quot;">​</a></h2><p>RAG（Retrieval-Augmented Generation）是一种通过在生成回答之前从外部知识库检索相关信息来增强 LLM 回答质量的技术。它不是完全依赖模型的参数记忆，而是在查询时提供最新的、领域特定的上下文。</p><h2 id="解决什么问题" tabindex="-1">解决什么问题？ <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题？&quot;">​</a></h2><p>LLM 有几个固有的局限性，RAG 可以解决这些问题：</p><ul><li><strong>知识截止</strong> — 模型的训练数据有截止日期；RAG 可以提供最新信息</li><li><strong>幻觉</strong> — 模型可能生成看似合理但错误的信息；RAG 让回答基于真实文档</li><li><strong>领域专业性</strong> — 通用模型缺乏专业领域的深度知识；RAG 可以注入领域特定的上下文</li><li><strong>来源追溯</strong> — RAG 可以将回答追溯到具体文档，支持引用和验证</li></ul><h2 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h2><p>一个标准的 RAG 流水线包含两个主要阶段：</p><h3 id="索引阶段" tabindex="-1">索引阶段 <a class="header-anchor" href="#索引阶段" aria-label="Permalink to &quot;索引阶段&quot;">​</a></h3><ol><li><strong>文档加载</strong> — 从各种来源（PDF、网页、数据库）加载文档</li><li><strong>分块</strong> — 将文档切分为更小的、语义连贯的片段</li><li><strong>向量化</strong> — 使用 Embedding 模型将片段转换为向量表示</li><li><strong>存储</strong> — 将向量连同元数据一起存入向量数据库</li></ol><h3 id="查询阶段" tabindex="-1">查询阶段 <a class="header-anchor" href="#查询阶段" aria-label="Permalink to &quot;查询阶段&quot;">​</a></h3><ol><li><strong>查询向量化</strong> — 将用户问题转换为向量</li><li><strong>检索</strong> — 从向量数据库中找到最相似的片段</li><li><strong>上下文组装</strong> — 将检索到的片段组合成 prompt</li><li><strong>生成</strong> — LLM 基于组装好的上下文生成回答</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文档 → 分块 → 向量化 → 向量数据库</span></span>
<span class="line"><span>                              ↓</span></span>
<span class="line"><span>用户查询 → 向量化 → 检索 → 上下文 → LLM → 回答</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p><strong>分块策略（Chunking）：</strong> 文档的切分方式显著影响检索质量。可选方案包括固定大小分块、基于句子的切分、递归字符切分和语义分块。正确的策略取决于数据和使用场景。</p><p><strong>Embedding 模型：</strong> 如 <code>text-embedding-ada-002</code>、<code>bge-large</code>、<code>e5</code> 等模型将文本转换为稠密向量。模型的选择直接影响检索精度。</p><p><strong>混合检索（Hybrid Retrieval）：</strong> 将稠密检索（向量相似度）与稀疏检索（BM25 关键词匹配）结合使用，通常优于单独使用任一种方法。</p><p><strong>重排序（Reranking）：</strong> 在初始检索之后，使用重排序模型（如 Cohere Rerank、BGE Reranker）重新排列结果以提高相关性。</p><p><strong>元数据过滤（Metadata Filtering）：</strong> 为片段添加元数据（来源、日期、类别），在相似度搜索之前先缩小结果范围。</p><h2 id="后续探索方向" tabindex="-1">后续探索方向 <a class="header-anchor" href="#后续探索方向" aria-label="Permalink to &quot;后续探索方向&quot;">​</a></h2><ul><li>高级分块策略（语义分块、命题级分块）</li><li>查询变换技术（HyDE、step-back prompting）</li><li>基于知识图谱的 Graph RAG</li><li>RAG 系统评估指标（忠实度、相关性、召回率）</li><li>生产环境考量：缓存、限流与成本控制</li></ul>`,21)])])}const u=e(o,[["render",i]]);export{c as __pageData,u as default};
